, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}]','타락한 제단과 어둠의 수정이 놓인 최종 전초 지점. 대사제의 기운이 느껴진다.'),(170,6,10,'저주받은 대사제',1,4,5,100,60,14,14,'dark','[{\"type\": \"stone\", \"coords\": [[6, 6], [7, 6], [6, 7], [7, 7]], \"height\": 5}, {\"type\": \"stone\", \"coords\": [[5, 5], [8, 5], [5, 8], [8, 8]], \"height\": 3}, {\"type\": \"stone\", \"coords\": [[5, 6], [5, 7], [8, 6], [8, 7], [6, 5], [7, 5], [6, 8], [7, 8]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[4, 4], [9, 4], [4, 9], [9, 9]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[3, 3], [10, 3], [3, 10], [10, 10]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[0, 6], [0, 7], [13, 6], [13, 7], [6, 0], [7, 0], [6, 13], [7, 13]], \"height\": 0}, {\"type\": \"dirt\", \"coords\": [[1, 1], [12, 1], [1, 12], [12, 12]], \"height\": 1}, {\"type\": \"stone\", \"coords\": [[2, 6], [2, 7], [11, 6], [11, 7], [6, 2], [7, 2], [6, 11], [7, 11]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 13, \"z\": 13}, {\"x\": 12, \"z\": 13}, {\"x\": 13, \"z\": 12}, {\"x\": 12, \"z\": 12}]','거대한 언데드 대사제가 암흑 마법을 휘두르는 최종 결전. 사원이 무너져 내리는 보스전.'),(171,15,1,'장승 길목',0,1,0,5,3,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','이끼 낀 장승이 양쪽에 서 있는 숲 입구. 무당이 매단 오색 천이 바람에 펄럭인다.'),(172,15,2,'도깨비 숲',0,1,1,10,6,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','고목 사이로 도깨비불이 하나둘 떠오른다. 발걸음 소리에 깔깔대는 웃음소리가 섞인다.'),(173,15,3,'달빛 제단',0,2,1,15,9,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','보름달 아래 돌로 쌓은 제단이 은빛으로 빛난다. 산짐승의 기운이 제단 주위를 맴돈다.'),(174,15,4,'구미호 영역',0,2,2,20,12,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','아홉 갈래 꼬리의 그림자가 나뭇잎 사이로 스친다. 매혹적인 향기가 판단력을 흐린다.'),(175,15,5,'독안개 늪',0,2,2,25,15,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','수렁에서 피어오르는 독한 안개. 도깨비불에 이끌려 들어가면 빠져나올 수 없다.'),(176,15,6,'신목 동굴',0,3,3,30,18,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','수백 년 은행나무 뿌리가 만든 동굴. 나무 정령의 숨결이 나뭇잎을 통해 속삭인다.'),(177,15,7,'호랑이 고개',0,3,3,35,21,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','바위에 깊은 발톱 자국이 남아 있다. 으르렁거리는 울림이 계곡을 타고 퍼져온다.'),(178,15,8,'무당골',0,3,4,40,24,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','깨진 부적과 놋쇠 방울이 뒹구는 버려진 굿당. 원혼의 기운이 공간을 지배한다.'),(179,15,9,'영혼의 경계',0,3,4,45,27,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','이승과 저승의 경계가 흐려지는 지대. 정처 없이 떠도는 혼백들이 눈에 보이기 시작한다.'),(180,15,10,'산군 호환',1,4,5,100,60,12,12,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 10, \"z\": 10}, {\"x\": 9, \"z\": 10}, {\"x\": 10, \"z\": 9}, {\"x\": 9, \"z\": 9}]','산을 다스리는 거대 백호가 포효하며 나타난다. 숲 전체가 진동하는 최종 보스전.'),(181,16,1,'돌계단',0,1,0,5,3,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','이끼 낀 돌계단으로 시작되는 산길. 절 가는 길에 걸린 기도 깃발이 아침 안개 속에 흔들린다.'),(182,16,2,'바위 절벽',0,1,1,10,6,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','깎아지른 절벽을 따라 난 좁은 길. 아래는 구름바다, 독수리가 머리 위를 선회한다.'),(183,16,3,'산사 암자',0,2,1,15,9,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','바위 틈에 지은 작은 암자. 풍경 소리와 고요한 독경이 산바람에 실려 온다.'),(184,16,4,'용소 폭포',0,2,2,20,12,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','무지개가 걸린 폭포 아래 깊은 소. 옛날 이무기가 수행했다는 전설이 전해진다.'),(185,16,5,'철쇄 비탈',0,2,2,25,15,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','쇠사슬에 의지해 올라야 하는 까마득한 바위 비탈. 발 아래 구름이 흘러간다.'),(186,16,6,'마애불 동굴',0,3,3,30,18,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','절벽에 새긴 거대한 마애불 앞 동굴. 촛불에 비친 불상의 눈이 살아있는 듯하다.'),(187,16,7,'구름다리',0,3,3,35,21,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','봉우리 사이를 잇는 흔들다리. 바람이 세차고 구름 사이로 나는 것 같은 아찔한 느낌.'),(188,16,8,'무장 능선',0,3,4,40,24,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','돌로 깎은 사천왕상이 늘어선 능선. 침입자가 다가오면 석상의 눈에서 빛이 난다.'),(189,16,9,'산신당',0,3,4,45,27,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','정상 부근의 산신각. 호랑이 그림과 백발 노인의 초상화가 모셔진 신성한 공간.'),(190,16,10,'산신령 강림',1,4,5,100,60,12,12,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 10, \"z\": 10}, {\"x\": 9, \"z\": 10}, {\"x\": 10, \"z\": 9}, {\"x\": 9, \"z\": 9}]','백호를 타고 폭풍 속에서 나타나는 산신령. 천둥과 벼락이 산 전체를 뒤흔드는 최종전.'),(191,18,1,'버려진 논',0,1,0,5,3,10,10,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','수확을 멈춘 지 오래된 황폐한 논. 허수아비에 부적이 붙어 있고 물안개가 자욱하다.'),(192,18,2,'수렁길',0,1,1,10,6,10,10,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','한 발 내디딜 때마다 발이 빠지는 검은 수렁. 거머리와 기이한 벌레들이 득시글한다.'),(193,18,3,'물귀신 늪',0,2,1,15,9,10,10,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','수면 아래에서 차가운 손이 발목을 잡는다. 물귀신의 원한이 서린 저주받은 물웅덩이.'),(194,18,4,'독버섯 군락',0,2,2,20,12,10,10,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','보랏빛 포자를 뿜는 거대 독버섯 지대. 환각을 일으키는 안개가 현실감을 앗아간다.'),(195,18,5,'침몰 마을',0,2,2,25,15,10,10,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','홍수에 잠긴 옛 마을. 지붕만 간신히 보이고 그 아래서 원혼들의 곡소리가 들린다.'),(196,18,6,'저주 제단',0,3,3,30,18,10,10,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','습지 한가운데 외딴 섬에 놓인 돌 제단. 금지된 굿이 행해진 저주받은 땅.'),(197,18,7,'도깨비불 밤',0,3,3,35,21,10,10,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','사방에서 푸른 불이 떠다니는 한밤의 늪. 불을 따라가면 더 깊은 수렁으로 빠진다.'),(198,18,8,'지네 소굴',0,3,4,40,24,10,10,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','거대한 나무 뿌리 사이에 만들어진 왕지네의 둥지. 독충과 독기가 가득하다.'),(199,18,9,'부패의 심장',0,3,4,45,27,10,10,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','늪의 모든 저주가 뿜어져 나오는 거대한 고목. 썩은 기운의 원천이 맥동하고 있다.'),(200,18,10,'이무기 부활',1,4,5,100,60,12,12,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 10, \"z\": 10}, {\"x\": 9, \"z\": 10}, {\"x\": 10, \"z\": 9}, {\"x\": 9, \"z\": 9}]','늪 깊은 곳에서 천 년을 기다린 이무기가 솟아오른다. 물기둥과 홍수의 최종 보스전.'),(201,17,1,'일주문',0,1,0,5,3,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','무너져 가는 일주문. 덩굴에 감긴 기둥 사이로 한때 장엄했던 사찰의 위용이 엿보인다.'),(202,17,2,'탑원',0,1,1,10,6,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','부서진 석등과 쓰러진 돌탑이 흩어진 마당. 승려 유령의 그림자가 어른거린다.'),(203,17,3,'대웅전',0,2,1,15,9,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','금이 간 불상이 서 있는 본전. 꺼지지 않는 촛불과 함께 어둠의 기운이 감돈다.'),(204,17,4,'범종루',0,2,2,20,12,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','금 간 거대 범종이 매달린 종루. 저주받은 종소리가 영혼을 불러모은다.'),(205,17,5,'장경각',0,2,2,25,15,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','흩어진 경전과 저주받은 두루마리가 떠다니는 경판 보관소. 어둠의 지식이 속삭인다.'),(206,17,6,'지하 부도전',0,3,3,30,18,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','사찰 아래 숨겨진 고승들의 부도. 봉인이 약해진 사리함에서 영혼이 새어 나온다.'),(207,17,7,'석탑 묘역',0,3,3,35,21,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','각 석탑마다 봉인된 원혼이 깃들어 있다. 봉인이 풀릴 때마다 빛이 흔들린다.'),(208,17,8,'선방',0,3,4,40,24,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','좌선 자세로 굳어진 승려 유령들이 즐비한 선방. 시간이 멈춘 듯한 소름 끼치는 고요.'),(209,17,9,'비로전',0,3,4,45,27,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','타락이 시작된 비밀 법당. 어둠의 사리가 안치된 제단에서 사악한 에너지가 흘러나온다.'),(210,17,10,'사천왕 각성',1,4,5,100,60,12,12,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 10, \"z\": 10}, {\"x\": 9, \"z\": 10}, {\"x\": 10, \"z\": 9}, {\"x\": 9, \"z\": 9}]','타락한 사천왕 석상이 깨어나 불의 심판을 내린다. 사찰이 무너지는 최종 보스전.'),(211,19,1,'황천 입구',0,1,0,5,3,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','이승과 저승의 경계에 선 안개 길. 현실이 옅어지며 주변이 점점 하얗게 변한다.'),(212,19,2,'영혼의 다리',0,1,1,10,6,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','황천강 위 놓인 은빛 다리를 건너는 혼백들. 달빛 아래 슬픈 행렬이 이어진다.'),(213,19,3,'첫째 전각',0,2,1,15,9,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','이승의 행적을 심판하는 첫 번째 대전. 저울 위에 놓인 영혼의 무게가 운명을 가른다.'),(214,19,4,'전생의 숲',0,2,2,20,12,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','나무마다 다른 전생이 비치는 기이한 숲. 기억의 나뭇잎이 바람에 흩날린다.'),(215,19,5,'망각의 강',0,2,2,25,15,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','이 물을 마시면 모든 기억을 잃는다. 강가에 주저앉아 우는 영혼들의 슬픈 풍경.'),(216,19,6,'혼시장',0,3,3,30,18,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','귀신 상인들이 영혼의 기운을 거래하는 저승의 시장. 기묘한 물건들이 즐비하다.'),(217,19,7,'진실의 거울',0,3,3,35,21,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','영혼의 진짜 모습을 비추는 거울들의 방. 환상이 깨지며 숨겨진 본성이 드러난다.'),(218,19,8,'형벌의 뜰',0,3,4,40,24,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','각종 형벌이 집행되는 저승의 마당. 비명 소리가 끊이지 않는 공포의 장소.'),(219,19,9,'윤회의 수레',0,3,4,45,27,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','카르마에 따라 다음 생을 결정하는 거대한 수레바퀴가 돌아가는 운명의 방.'),(220,19,10,'염라대왕',1,4,5,100,60,12,12,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 10, \"z\": 10}, {\"x\": 9, \"z\": 10}, {\"x\": 10, \"z\": 9}, {\"x\": 9, \"z\": 9}]','저승을 다스리는 염라대왕의 심판. 사후 세계의 지배자와의 우주적 최종 결전.'),(221,20,1,'이끼 토리이',0,1,0,5,3,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','이끼에 덮인 토리이 문이 삼나무 숲으로 안내한다. 코다마 정령의 울림이 들린다.'),(222,20,2,'대나무 미로',0,1,1,10,6,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','바스락거리는 소리와 함께 너구리 그림자가 스친다. 신비한 등불이 길을 비춘다.'),(223,20,3,'금줄 신목',0,2,1,15,9,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','시메나와가 감긴 거대한 고목. 성스럽지만 타락한 기운이 땅속 깊은 곳에서 올라온다.'),(224,20,4,'여우 사당',0,2,2,20,12,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','버려진 봉납함과 깨진 여우 석상이 있는 숲속 사당. 기묘한 정적이 흐른다.'),(225,20,5,'수해 깊은 숲',0,2,2,25,15,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','주가이가하라를 닮은 숲. 뒤틀린 나무들, 방황하는 영혼들, 나침반이 돌아간다.'),(226,20,6,'코다마 골짜기',0,3,3,30,18,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','수백 개의 나무 정령이 빛을 내며 노래하는 아름답고 초자연적인 공간.'),(227,20,7,'킷수네 시험',0,3,3,35,21,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','여우가 강가에서 기다린다. 환술과 속임의 시험을 통과해야 길이 열린다.'),(228,20,8,'황혼 요괴',0,3,4,40,24,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','해질녘이 되자 요괴들이 하나둘 모습을 드러낸다. 숲이 완전히 다른 세계로 바뀐다.'),(229,20,9,'오염된 신목',0,3,4,45,27,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','고목이 죽어가고 있다. 어둠의 요괴들이 모여들어 숲의 마지막 생명력을 빨아들인다.'),(230,20,10,'조로구모',1,4,5,100,60,12,12,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 10, \"z\": 10}, {\"x\": 9, \"z\": 10}, {\"x\": 10, \"z\": 9}, {\"x\": 9, \"z\": 9}]','거미줄에 뒤덮인 숲에서 거대한 거미 마녀 조로구모가 나타난다. 요괴숲 최종 보스전.'),(231,21,1,'돌계단 참배',0,1,0,5,3,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','붉은 토리이가 이어지는 돌계단. 삼나무 사이로 아침 햇살이 비쳐든다.'),(232,21,2,'폭포 수행',0,1,1,10,6,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','야마부시 수행자가 찬 폭포 아래서 정신을 단련하는 영적 수련의 장소.'),(233,21,3,'텐구의 흔적',0,2,1,15,9,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','바위 길에 텐구의 깃털이 떨어져 있다. 경고의 표식들, 바람이 세차게 분다.'),(234,21,4,'비전 동굴',0,2,2,20,12,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','텐구의 수행터였던 동굴. 고대 두루마리와 무술 비기가 바위에 새겨져 있다.'),(235,21,5,'구름 위 다리',0,2,2,25,15,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','구름 아래로 까마귀 텐구들이 선회하는 아찔한 다리. 담력의 시험장.'),(236,21,6,'온천 휴식처',0,3,3,30,18,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','요괴들도 평화롭게 목욕하는 산속 온천. 일시적 휴전 지대.'),(237,21,7,'뇌격 봉',0,3,3,35,21,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','벼락에 맞은 봉우리. 뇌신의 에너지가 치직거리며 위험한 접근로를 만든다.'),(238,21,8,'승병 사찰',0,3,4,40,24,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','무술을 익힌 승려들이 수행하는 산중 사찰. 무(武)와 선(禪)이 하나가 되는 곳.'),(239,21,9,'정상 관문',0,3,4,45,27,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','신풍이 몰아치고 텐구 수호자들이 마지막 길을 막아서는 최후의 관문.'),(240,21,10,'대텐구',1,4,5,100,60,12,12,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 10, \"z\": 10}, {\"x\": 9, \"z\": 10}, {\"x\": 10, \"z\": 9}, {\"x\": 9, \"z\": 9}]','부채 하나로 신풍을 일으키는 대텐구와의 결전. 산의 힘이 폭발하는 최종 보스전.'),(241,22,1,'인왕문',0,1,0,5,3,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','금강역사상이 지키는 웅장한 사찰 정문. 돌등이 줄지어 서고 단풍잎이 흩날린다.'),(242,22,2,'모래 정원',0,1,1,10,6,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','정성스레 정돈된 모래 무늬가 어지럽혀져 있다. 정체불명의 발자국이 남아 있다.'),(243,22,3,'본존 법당',0,2,1,15,9,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','피눈물을 흘리는 불상과 저주받은 경전이 떠다니는 본전. 신성이 오염되어 있다.'),(244,22,4,'오층탑',0,2,2,20,12,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','각 층마다 더 깊은 어둠에 빠진 오층 탑. 올라갈수록 요괴가 기다린다.'),(245,22,5,'묘지',0,2,2,25,15,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','비석이 기울어지고 흙 사이로 손이 뻗어 나오는 사찰 뒤편 묘지. 언데드의 영역.'),(246,22,6,'범종각',0,3,3,30,18,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','금 간 범종이 저주의 음파를 만든다. 소리가 방향감각을 혼란스럽게 한다.'),(247,22,7,'비밀 지하도',0,3,3,35,21,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','벽에 오니 가면이 걸린 숨겨진 지하 통로. 함정 장치가 곳곳에 설치되어 있다.'),(248,22,8,'보물 창고',0,3,4,40,24,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','저주받은 유물들이 활성화되어 스스로 움직이며 공격해 오는 위험한 수장고.'),(249,22,9,'만다라 내전',0,3,4,45,27,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','거대한 만다라가 어둠의 에너지로 빛나며 차원의 균열이 벌어지는 최심부.'),(250,22,10,'천수관음',1,4,5,100,60,12,12,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 10, \"z\": 10}, {\"x\": 9, \"z\": 10}, {\"x\": 10, \"z\": 9}, {\"x\": 9, \"z\": 9}]','빙의된 천수관음 거대 석상이 천 개의 팔로 공격한다. 신성과 마성의 최종 보스전.'),(251,23,1,'해식 동굴',0,1,0,5,3,10,10,'water',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','파도가 부서지는 해안가 동굴. 반쯤 잠긴 토리이 너머로 제물 조개가 놓여 있다.'),(252,23,2,'산호 참배',0,1,1,10,6,10,10,'water',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','산호로 뒤덮인 수중 토리이 문. 바다거북이 안내하고 생물 발광이 길을 비춘다.'),(253,23,3,'유령 어촌',0,2,1,15,9,10,10,'water',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','침몰한 어촌에서 유령 어부들이 여전히 일하고 있다. 그물이 떠다니는 슬픈 풍경.'),(254,23,4,'산호 정원',0,2,2,20,12,10,10,'water',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','해룡의 산호 정원. 거대한 산호 조형물 사이로 해마 기사단이 순찰 중이다.'),(255,23,5,'갓파 영역',0,2,2,25,15,10,10,'water',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','수중 하천의 물살이 거센 갓파의 영토. 오이 제물이 떠다니고 있다.'),(256,23,6,'닌교 만',0,3,3,30,18,10,10,'water',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','인어의 슬픈 노랫소리가 울리는 해만. 아름답지만 깊이 빠져들면 돌아오지 못한다.'),(257,23,7,'유령선 묘지',0,3,3,35,21,10,10,'water',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','후나유레이의 유령선들이 잠들어 있는 해저 묘지. 등불이 어둠 속에서 흔들린다.'),(258,23,8,'진주 궁전',0,3,4,40,24,10,10,'water',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','거대한 진주가 빛나는 궁전. 보물과 함정이 공존하는 탐욕의 시험장.'),(259,23,9,'심연 접근',0,3,4,45,27,10,10,'water',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','우미보즈의 그림자가 아래서 어른거린다. 수압이 높아지고 어둠이 짙어지는 심해.'),(260,23,10,'류진',1,4,5,100,60,12,12,'water',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 10, \"z\": 10}, {\"x\": 9, \"z\": 10}, {\"x\": 10, \"z\": 9}, {\"x\": 9, \"z\": 9}]','용궁의 왕좌에서 일어선 해룡왕 류진. 쓰나미와 소용돌이의 최종 보스전.'),(261,24,1,'경계의 문',0,1,0,5,3,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','무너져가는 토리이를 지나면 영혼들이 흘러가는 황혼의 길이 펼쳐진다.'),(262,24,2,'사자의 행렬',0,1,1,10,6,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','한 방향으로만 걸어가는 창백한 영혼들. 종이 등불이 길을 밝히는 슬픈 행렬.'),(263,24,3,'삼도천',0,2,1,15,9,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','얕은 여울, 다리, 깊은 물살의 세 갈래 길. 생전의 업에 따라 건너는 곳이 달라진다.'),(264,24,4,'아귀 벌판',0,2,2,20,12,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','영원한 굶주림에 시달리는 아귀(가키)들이 구걸하는 처참한 들판.'),(265,24,5,'엔마 법정',0,2,2,25,15,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','엔마 대왕이 죄를 저울질하는 법정. 진실을 비추는 거대한 거울이 서 있다.'),(266,24,6,'빙한 지옥',0,3,3,30,18,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','얼어붙은 죄인들이 있는 얼음 지옥. 수정 얼음 속에 갇힌 영혼들이 보인다.'),(267,24,7,'화염 지옥',0,3,3,35,21,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','불타는 대지 위에 비명이 가득한 화염 지옥. 견딜 수 없는 열기가 몰려온다.'),(268,24,8,'검산 지옥',0,3,4,40,24,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','영혼들이 칼날 위를 걸어야 하는 검의 산. 끝없는 고통의 형벌이 이어진다.'),(269,24,9,'시니가미 궁',0,3,4,45,27,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','죽음의 신들이 모여 있는 사신의 궁전. 불길한 장엄함이 감도는 어둠의 전당.'),(270,24,10,'시니가미',1,4,5,100,60,12,12,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 10, \"z\": 10}, {\"x\": 9, \"z\": 10}, {\"x\": 10, \"z\": 9}, {\"x\": 9, \"z\": 9}]','대낫을 든 시니가미와의 결전. 영혼을 거두는 사신의 심판, 최종 보스전.'),(271,25,1,'석사자 입구',0,1,0,5,3,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','고대 돌사자 한 쌍이 지키는 비취색 안개의 숲 입구. 산해경의 세계가 시작된다.'),(272,25,2,'판다 영림',0,1,1,10,6,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','영적 판다들이 서식하는 대나무 숲. 고대 무사의 유령이 수련을 계속하고 있다.'),(273,25,3,'산해경 영역',0,2,1,15,9,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','신화의 기이한 짐승들이 나타나는 구역. 책에서만 보던 존재들이 눈앞에 있다.'),(274,25,4,'반도 신목',0,2,2,20,12,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','불로장생의 복숭아가 열리는 거대한 나무. 금빛 과일이 유혹적으로 빛난다.'),(275,25,5,'호리정 굴',0,2,2,25,15,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','여우 요정(호리정)의 소굴. 아름다움과 위험이 공존하는 환술의 미궁.'),(276,25,6,'약초원',0,3,3,30,18,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','신화 속 약초가 자라는 비밀 정원. 만병통치와 치명적 독초가 나란히 자란다.'),(277,25,7,'오동 괴목',0,3,3,35,21,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','사악한 정령이 둥지를 튼 썩어가는 오동나무. 어둠의 에너지가 숲에 퍼진다.'),(278,25,8,'토지묘',0,3,4,40,24,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','숲을 관장하는 토지신의 작은 사당. 제물이 놓여 있지만 신은 떠난 듯하다.'),(279,25,9,'천년 수목',0,3,4,45,27,10,10,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','천 년을 살아 정신이 깨어난 거대 나무 정령. 고대의 지혜와 대면하는 곳.'),(280,25,10,'산해경 마수',1,4,5,100,60,12,12,'grass',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 10, \"z\": 10}, {\"x\": 9, \"z\": 10}, {\"x\": 10, \"z\": 9}, {\"x\": 9, \"z\": 9}]','산해경에서 빠져나온 태고의 마수와의 결전. 원시 자연의 분노가 폭발하는 최종전.'),(281,26,1,'석문 입산',0,1,0,5,3,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','도교 부적이 새겨진 돌 아치문. 순례자들이 오르는 신선의 산이 시작된다.'),(282,26,2,'다정',0,1,1,10,6,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','현자가 신비의 차를 우려내는 구름 위의 정자. 아래로 운해가 끝없이 펼쳐진다.'),(283,26,3,'연단 동굴',0,2,1,15,9,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','불로장생의 단약을 달이는 도교 연금술 동굴. 신비로운 재료들이 부글거린다.'),(284,26,4,'수렴 폭포',0,2,2,20,12,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','용이 새겨진 폭포. 물줄기 뒤에 숨겨진 동굴이 있다는 전설이 전해진다.'),(285,26,5,'운중 보도',0,2,2,25,15,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','구름 위를 밟고 걷는 길. 천상계에 가까워지며 현기증이 밀려온다.'),(286,26,6,'무림 사찰',0,3,3,30,18,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','운무 속 무술 승려들이 수행하는 사찰. 구름 속에서 쿵후를 익히는 장관.'),(287,26,7,'옥석 광맥',0,3,3,35,21,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','영적 옥이 빛나는 광맥. 초록빛 광물의 부가 가득하지만 수호자가 지킨다.'),(288,26,8,'신선 바둑판',0,3,4,40,24,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','두 신선이 바둑을 두고 있다. 시간이 다르게 흐르는 기묘한 정자.'),(289,26,9,'곤륜 도관',0,3,4,45,27,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','천상 에너지가 수렴하는 산 정상의 도교 사원. 신의 영역에 다가선다.'),(290,26,10,'타락 신선',1,4,5,100,60,12,12,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 10, \"z\": 10}, {\"x\": 9, \"z\": 10}, {\"x\": 10, \"z\": 9}, {\"x\": 9, \"z\": 9}]','어둠에 물든 신선과의 결전. 타락한 곤륜의 힘이 폭발하는 최종 보스전.'),(291,27,1,'산문',0,1,0,5,3,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','돌사자 한 쌍이 지키는 거대 산문. 붉은 등롱이 즐비하고 향 연기가 자욱하다.'),(292,27,2,'향전',0,1,1,10,6,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','수천 개의 향이 타오르는 전당. 연기가 얼굴 형상을 만들어내 압도적이다.'),(293,27,3,'천왕전',0,2,1,15,9,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','네 천왕의 거대 석상이 무기를 들고 서 있다. 그 위압감에 발걸음이 멈춘다.'),(294,27,4,'보리수 마당',0,2,2,20,12,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','타락한 보리수에서 어둠의 뿌리가 뻗어 나간다. 승려들이 달아난 흔적이 있다.'),(295,27,5,'지하 진신사리',0,2,2,25,15,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','사찰 창건주의 사리가 안치된 지하 묘. 토용 수호병이 경비를 서고 있다.'),(296,27,6,'대장경각',0,3,3,30,18,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','금강경이 공중에 떠서 방어 결계를 형성하고 있다. 신성한 지식의 보고.'),(297,27,7,'진마탑',0,3,3,35,21,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','악을 가두는 봉인탑. 봉인이 약해지며 균열 사이로 사악한 에너지가 새어 나온다.'),(298,27,8,'오백나한전',0,3,4,40,24,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','500 나한 석상의 눈이 빛나며 경비를 선다. 침입자를 감시하는 무서운 수호자들.'),(299,27,9,'관음전',0,3,4,45,27,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','거대한 관음 석상이 자비에서 심판으로 변한 내전. 어둠의 자비가 가득하다.'),(300,27,10,'사천왕 분노',1,4,5,100,60,12,12,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 10, \"z\": 10}, {\"x\": 9, \"z\": 10}, {\"x\": 10, \"z\": 9}, {\"x\": 9, \"z\": 9}]','깨어난 사대천왕이 합체하여 분노를 폭발시킨다. 사찰이 흔들리는 최종 보스전.'),(301,28,1,'저주받은 논',0,1,0,5,3,10,10,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','허수아비에 부적 얼굴이 달린 버려진 논. 안개가 자욱하고 어딘가에서 뛰는 소리가.'),(302,28,2,'독충 영역',0,1,1,10,6,10,10,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','기묘한 벌레와 거머리가 득시글한 독늪. 고독(蠱毒) 지역의 시작.'),(303,28,3,'강시 마을',0,2,1,15,9,10,10,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','가라앉은 마을에서 강시들이 미동 없이 서 있다. 해가 지면 뛰기 시작한다.'),(304,28,4,'독련 연못',0,2,2,20,12,10,10,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','아름답지만 치명적인 연꽃이 핀 연못. 두꺼비 요괴의 소리가 울려 퍼진다.'),(305,28,5,'무녀 오두막',0,2,2,25,15,10,10,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','묘족 무녀의 버려진 집. 고독 항아리와 벌레 사육 통이 즐비한 사술의 장소.'),(306,28,6,'지전 묘지',0,3,3,30,18,10,10,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','지전(紙錢)이 썩어가는 늪지 묘지. 배고픈 귀신들이 모여드는 음침한 곳.'),(307,28,7,'귀곡 논',0,3,3,35,21,10,10,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','유령 농부들이 끝없는 추수를 반복하는 저주받은 논. 죽음의 수확이 이어진다.'),(308,28,8,'거미정 영역',0,3,4,40,24,10,10,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','비단 덫이 사방에 깔린 거미정(蜘蛛精)의 영역. 실크 함정이 가득하다.'),(309,28,9,'저주의 우물',0,3,4,45,27,10,10,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','어둠이 부글거리며 솟아오르는 우물. 늪의 모든 저주가 이곳에서 시작되었다.'),(310,28,10,'강시왕',1,4,5,100,60,12,12,'swamp',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 10, \"z\": 10}, {\"x\": 9, \"z\": 10}, {\"x\": 10, \"z\": 9}, {\"x\": 9, \"z\": 9}]','청나라 관복의 강시왕이 군대를 이끌고 일어난다. 부적 대결의 최종 보스전.'),(311,29,1,'귀문관',0,1,0,5,3,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','거대한 철문에 귀신 병사가 경비를 서는 지부(地府)의 관문. 중국 저승의 시작.'),(312,29,2,'나하교',0,1,1,10,6,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','망각의 강 위 세 갈래 다리. 생전의 업에 따라 건너는 길이 달라지는 운명의 다리.'),(313,29,3,'진광 법정',0,2,1,15,9,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','첫 번째 명왕 진광왕이 생전의 행적을 심판한다. 전생을 비추는 거울이 서 있다.'),(314,29,4,'업경대',0,2,2,20,12,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','모든 죄를 낱낱이 보여주는 거울. 숨길 곳이 없는 냉혹한 진실의 장소.'),(315,29,5,'도산',0,2,2,25,15,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','칼날 위를 걸어야 하는 영혼들의 산. 비명 소리 가득한 형벌의 공포.'),(316,29,6,'유정',0,3,3,30,18,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','끓는 기름에 빠진 죄인들이 벌 받는 유정. 치솟는 열기와 고통의 형벌.'),(317,29,7,'윤회 전각',0,3,3,35,21,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','육도(六道)의 수레바퀴가 도는 전각. 카르마가 다음 생을 결정하는 운명의 방.'),(318,29,8,'맹파정',0,3,4,40,24,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','할머니 맹파가 망각의 차를 끓이는 정자. 영혼들이 줄지어 마시며 기억을 잊는다.'),(319,29,9,'우두마면 초소',0,3,4,45,27,10,10,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]','소 머리와 말 얼굴의 저승 문지기가 순찰하는 초소. 마지막 관문이 다가온다.'),(320,29,10,'염라왕',1,4,5,100,60,12,12,'stone',NULL,'[{\"x\": 1, \"z\": 1}, {\"x\": 2, \"z\": 1}, {\"x\": 1, \"z\": 2}]','[{\"x\": 10, \"z\": 10}, {\"x\": 9, \"z\": 10}, {\"x\": 10, \"z\": 9}, {\"x\": 9, \"z\": 9}]','지부를 다스리는 염라왕의 심판대. 우주적 정의를 건 최종 보스전.');
