DROP TABLE IF EXISTS `dungeon_tickets`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `dungeon_tickets` (
  `id` int NOT NULL AUTO_INCREMENT,
  `dungeon_key` varchar(50) NOT NULL,
  `name` varchar(100) NOT NULL,
  `icon` varchar(10) DEFAULT 0xF09F8EAB,
  `grade` enum('일반','고급','희귀','영웅','전설') DEFAULT '일반',
  `description` varchar(200) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_dungeon_ticket` (`dungeon_key`)
) ENGINE=InnoDB AUTO_INCREMENT=2993 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
