INSERT INTO `dungeon_tickets` VALUES (1,'forest','어둠의 숲 입장권','🌲','일반','어둠의 숲에 입장할 수 있는 티켓.'),(2,'slime_cave','슬라임 동굴 입장권','🟢','일반','슬라임 동굴에 입장할 수 있는 티켓.'),(3,'cave','지하 동굴 입장권','🕳️','고급','지하 동굴에 입장할 수 있는 티켓.'),(4,'swamp','독안개 늪 입장권','🌿','고급','독안개 늪에 입장할 수 있는 티켓.'),(5,'goblin','도깨비 마을 입장권','👺','고급','도깨비 마을에 입장할 수 있는 티켓.'),(6,'mountain','영혼의 산 입장권','🏔️','희귀','영혼의 산에 입장할 수 있는 티켓.'),(7,'ocean','해저 유적 입장권','🌊','희귀','해저 유적에 입장할 수 있는 티켓.'),(8,'spirit_forest','정령의 숲 입장권','🧚','희귀','정령의 숲에 입장할 수 있는 티켓.'),(9,'temple','폐허 사원 입장권','🏛️','영웅','폐허 사원에 입장할 수 있는 티켓.'),(10,'demon','마계 균열 입장권','😈','영웅','마계 균열에 입장할 수 있는 티켓.'),(11,'dragon','용의 둥지 입장권','🐉','전설','용의 둥지에 입장할 수 있는 티켓.');
