  `id` int NOT NULL AUTO_INCREMENT,
  `key_name` varchar(50) NOT NULL,
  `name` varchar(100) NOT NULL,
  `description` varchar(300) DEFAULT NULL,
  `icon` varchar(10) DEFAULT 0xF09F97BAEFB88F,
  `required_level` int DEFAULT '1',
  `map_width` int DEFAULT '10',
  `map_height` int DEFAULT '10',
  `base_tile_type` varchar(20) DEFAULT 'grass',
  `tile_overrides` json DEFAULT NULL,
  `player_spawns` json DEFAULT NULL,
  `monster_spawns` json DEFAULT NULL,
  `display_order` int DEFAULT '0',
  PRIMARY KEY (`id`),
  UNIQUE KEY `key_name` (`key_name`)
) ENGINE=InnoDB AUTO_INCREMENT=131 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
