INSERT INTO `dungeons` VALUES (4,'forest','어둠의 숲','고대의 저주가 스며든 어둠의 숲. 뒤틀린 나무들 사이로 불길한 안개가 피어오르고, 달빛조차 닿지 않는 깊은 곳에서는 정체불명의 울음소리가 메아리친다. 약한 몬스터들이 서식하지만, 숲 깊숙이 들어갈수록 강력한 존재가 숨어 있다. 초보 모험가들의 첫 시련장.','🌲',1,10,10,'grass','[{\"type\": \"grass\", \"coords\": [[2, 2], [2, 3], [3, 2], [3, 3]], \"height\": 1}, {\"type\": \"grass\", \"coords\": [[3, 3]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[0, 5], [1, 5], [2, 5], [3, 5], [4, 5], [5, 5], [6, 5], [7, 5], [8, 5], [9, 5]], \"height\": 0}, {\"type\": \"water\", \"coords\": [[7, 2], [7, 3], [8, 2]], \"height\": 0}, {\"type\": \"stone\", \"coords\": [[6, 7], [6, 8], [7, 7]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',1),(5,'cave','지하 동굴','대지의 심장부로 이어지는 깊은 지하 동굴. 거대한 종유석과 석순이 숲을 이루고, 지하 강이 푸른 빛으로 흐른다. 고대 문명의 흔적이 벽면에 새겨져 있으며, 어둠 속에서 바위처럼 숨어 있다가 갑자기 습격하는 강력한 몬스터들이 도사린다.','🕳️',2,10,10,'stone','[{\"type\": \"stone\", \"coords\": [[0, 4], [0, 5], [1, 4], [1, 5]], \"height\": 3}, {\"type\": \"stone\", \"coords\": [[4, 0], [4, 1], [5, 0], [5, 1]], \"height\": 1}, {\"type\": \"stone\", \"coords\": [[4, 2], [5, 2]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[3, 6], [3, 7], [4, 6], [4, 7]], \"height\": 0}, {\"type\": \"dirt\", \"coords\": [[7, 4], [7, 5], [7, 6], [8, 4], [8, 5], [8, 6]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}]',3),(6,'temple','폐허 사원','고대의 사악한 의식이 벌어졌던 저주받은 사원. 부서진 석상들 사이로 보라색 저주의 기운이 소용돌이치고, 지하에는 봉인된 어둠이 서서히 깨어나고 있다. 언데드 승려와 원혼들이 배회하며, 최심부의 대사제는 죽음 이후에도 광기에 사로잡혀 있다.','🏚️',4,10,10,'dark','[{\"type\": \"stone\", \"coords\": [[4, 4], [4, 5], [5, 4], [5, 5]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[4, 3], [5, 3], [4, 6], [5, 6], [3, 4], [3, 5], [6, 4], [6, 5]], \"height\": 1}, {\"type\": \"stone\", \"coords\": [[2, 2], [7, 2], [2, 7], [7, 7]], \"height\": 3}, {\"type\": \"water\", \"coords\": [[0, 9], [1, 9], [9, 0], [9, 1]], \"height\": 0}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 7, \"z\": 9}]',9),(7,'swamp','독안개 늪','독기와 장기가 자욱한 저주받은 늪지대. 보라색 안개가 시야를 가리고, 부패한 나무들 사이로 거대 곤충과 독성 식물이 위협한다. 늪 아래에서는 알 수 없는 존재가 끊임없이 거품을 일으키며, 한번 빠지면 빠져나오기 힘든 위험지대다.','🌿',2,10,10,'grass','[{\"type\": \"water\", \"coords\": [[2, 2], [3, 2], [4, 2], [2, 3], [3, 3], [4, 3], [2, 4], [3, 4]], \"height\": 0}, {\"type\": \"water\", \"coords\": [[6, 6], [7, 6], [6, 7], [7, 7], [8, 7]], \"height\": 0}, {\"type\": \"dirt\", \"coords\": [[5, 0], [5, 1], [5, 2]], \"height\": 1}, {\"type\": \"stone\", \"coords\": [[0, 8], [1, 8], [0, 9]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',4),(8,'mountain','영혼의 산','원혼과 요괴가 떠도는 유령의 산. 바람 소리에 실린 귀곡성이 등산객을 미혹하고, 고대 산신당의 등불이 길을 잃게 만든다. 산 정상에는 강력한 산신령이 깃들어 있으며, 높이 오를수록 현실과 영계의 경계가 희미해져 더욱 위험해진다.','⛰️',3,10,10,'stone','[{\"type\": \"stone\", \"coords\": [[4, 4], [5, 4], [4, 5], [5, 5]], \"height\": 4}, {\"type\": \"stone\", \"coords\": [[3, 3], [6, 3], [3, 6], [6, 6]], \"height\": 3}, {\"type\": \"stone\", \"coords\": [[2, 2], [7, 2], [2, 7], [7, 7]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[1, 1], [8, 1], [1, 8], [8, 8]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[0, 5], [9, 5]], \"height\": 0}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',6),(9,'demon','마계 균열','인간 세계와 마계를 잇는 차원의 균열. 현실이 왜곡되어 하늘이 핏빛으로 물들고, 지옥의 불꽃과 유황 냄새가 진동한다. 균열을 통해 쏟아져 나오는 악마와 마족은 점점 강해지고 있으며, 균열 너머에는 마왕이 침공의 기회를 엿보고 있다.','🌋',5,10,10,'dark','[{\"type\": \"water\", \"coords\": [[4, 4], [5, 4], [4, 5], [5, 5]], \"height\": 0}, {\"type\": \"stone\", \"coords\": [[3, 3], [6, 3], [3, 6], [6, 6]], \"height\": 2}, {\"type\": \"dark\", \"coords\": [[1, 1], [8, 1], [1, 8], [8, 8]], \"height\": 3}, {\"type\": \"stone\", \"coords\": [[0, 4], [0, 5], [9, 4], [9, 5]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',10),(10,'dragon','용의 둥지','태고의 용이 잠든 화산 심장부. 용암의 강이 흐르고, 거대한 용의 뼈가 동굴 벽면에 박혀 있다. 수천 년간 축적된 보물 더미가 빛나지만, 고대의 용은 여전히 살아 숨 쉬며 자신의 영역을 침범한 자를 용서하지 않는다. 최강의 도전.','🐉',7,12,12,'stone','[{\"type\": \"stone\", \"coords\": [[5, 5], [6, 5], [5, 6], [6, 6]], \"height\": 3}, {\"type\": \"stone\", \"coords\": [[4, 4], [7, 4], [4, 7], [7, 7]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[3, 5], [3, 6], [8, 5], [8, 6], [5, 3], [6, 3], [5, 8], [6, 8]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[0, 0], [11, 0], [0, 11], [11, 11]], \"height\": 0}, {\"type\": \"stone\", \"coords\": [[1, 5], [1, 6], [10, 5], [10, 6]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 10, \"z\": 10}, {\"x\": 11, \"z\": 10}, {\"x\": 10, \"z\": 11}, {\"x\": 11, \"z\": 11}]',11),(11,'ocean','해저 유적','바다 밑에 가라앉은 태고의 유적. 산호로 뒤덮인 기둥들과 해초에 휘감긴 신전이 심해의 어둠 속에서 신비로운 빛을 발한다. 수생 몬스터들의 절대적 영역이며, 유적 깊은 곳에는 전설의 바다뱀이 잠들어 있다는 전설이 전해진다.','🌊',4,10,10,'stone','[{\"type\": \"water\", \"coords\": [[0, 0], [1, 0], [0, 1], [9, 0], [9, 1], [8, 0], [0, 9], [1, 9], [0, 8], [9, 9], [8, 9], [9, 8]], \"height\": 0}, {\"type\": \"stone\", \"coords\": [[3, 3], [4, 3], [5, 3], [6, 3], [3, 4], [6, 4], [3, 5], [6, 5], [3, 6], [4, 6], [5, 6], [6, 6]], \"height\": 1}, {\"type\": \"stone\", \"coords\": [[4, 4], [5, 4], [4, 5], [5, 5]], \"height\": 2}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',7),(12,'goblin','도깨비 마을','장난기 넘치는 도깨비들이 모여 사는 무법 마을. 훔친 보물들로 가득한 오두막, 기상천외한 함정들, 그리고 끝없는 축제가 벌어지는 곳. 만만해 보이지만 도깨비 방망이의 힘은 무시할 수 없으며, 마을 깊숙이 자리한 도깨비 왕은 엄청난 전투력을 자랑한다.','👺',3,10,10,'grass','[{\"type\": \"stone\", \"coords\": [[2, 2], [3, 2], [2, 3]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[6, 6], [7, 6], [7, 7]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[4, 0], [5, 0], [4, 1], [5, 1]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[0, 8], [1, 8], [2, 8], [0, 9], [1, 9], [2, 9]], \"height\": 0}, {\"type\": \"grass\", \"coords\": [[8, 2], [9, 2], [8, 3]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',5),(13,'spirit_forest','정령의 숲','네 원소의 정령들이 깃든 신비의 숲. 불·물·땅·바람의 에너지가 하나로 수렴하는 세계수가 중심에 서 있고, 계절이 동시에 존재하는 환상적인 경관이 펼쳐진다. 정령의 시련을 통과한 자만이 원소의 축복을 받을 수 있다.','✨',4,10,10,'grass','[{\"type\": \"water\", \"coords\": [[2, 4], [2, 5], [3, 4], [3, 5]], \"height\": 0}, {\"type\": \"water\", \"coords\": [[6, 2], [7, 2], [6, 3], [7, 3]], \"height\": 0}, {\"type\": \"grass\", \"coords\": [[4, 4], [5, 4], [4, 5], [5, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[1, 1], [8, 1], [1, 8], [8, 8]], \"height\": 1}, {\"type\": \"stone\", \"coords\": [[0, 0], [9, 9]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',8),(14,'slime_cave','슬라임 동굴','형형색색의 슬라임들이 가득한 수정 동굴. 벽면의 발광 수정이 몽환적인 빛을 내뿜고, 바닥에는 끈적끈적한 점액이 흐른다. 귀여워 보이지만, 강산성 체액을 가진 슬라임부터 불꽃·얼음·독 슬라임까지 다양한 위험이 도사리고 있다.','🫧',1,10,10,'stone','[{\"type\": \"water\", \"coords\": [[3, 3], [4, 3], [5, 3], [3, 4], [5, 4], [3, 5], [4, 5], [5, 5]], \"height\": 0}, {\"type\": \"stone\", \"coords\": [[4, 4]], \"height\": 1}, {\"type\": \"stone\", \"coords\": [[7, 1], [8, 1], [7, 2]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[1, 7], [2, 7], [1, 8]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',2),(15,'kr_forest','한국: 고조선 숲','한국의 신비로운 숲. 장승과 도깨비, 구미호가 서식하는 수묵화 같은 어둠의 원시림.','🌲',1,10,10,'grass','[{\"type\": \"stone\", \"coords\": [[4, 4], [5, 4], [4, 5], [5, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[2, 2], [7, 7]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[7, 2], [2, 7]], \"height\": 0}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',12),(16,'kr_mountain','한국: 백두산','산신령이 다스리는 한국의 영산. 사천왕과 석인, 폭풍의 산신이 수행자를 시험한다.','⛰️',3,10,10,'stone','[{\"type\": \"stone\", \"coords\": [[4, 4], [5, 4], [4, 5], [5, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[2, 2], [7, 7]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[7, 2], [2, 7]], \"height\": 0}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',13),(17,'kr_temple','한국: 고찰 폐허','타락한 사천왕이 지키는 폐사찰. 깨진 범종 소리가 원혼을 불러모으는 금지의 성역.','🏚️',5,10,10,'dark','[{\"type\": \"stone\", \"coords\": [[4, 4], [5, 4], [4, 5], [5, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[2, 2], [7, 7]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[7, 2], [2, 7]], \"height\": 0}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',15),(18,'kr_swamp','한국: 장자못','물귀신과 독충이 도사리는 저주받은 습지. 이무기가 천 년의 잠에서 깨어나려 한다.','🌿',4,10,10,'grass','[{\"type\": \"stone\", \"coords\": [[4, 4], [5, 4], [4, 5], [5, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[2, 2], [7, 7]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[7, 2], [2, 7]], \"height\": 0}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',14),(19,'kr_spirit','한국: 신령의 숲','이승과 저승의 경계. 염라대왕의 심판을 받으러 가는 영혼의 길, 황천으로의 여정.','✨',6,10,10,'grass','[{\"type\": \"stone\", \"coords\": [[4, 4], [5, 4], [4, 5], [5, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[2, 2], [7, 7]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[7, 2], [2, 7]], \"height\": 0}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',16),(20,'jp_forest','일본: 아오키가하라','요괴가 서식하는 일본의 어둠의 숲. 코다마와 킷수네, 조로구모가 기다리는 마의 원림.','🌲',1,10,10,'grass','[{\"type\": \"stone\", \"coords\": [[4, 4], [5, 4], [4, 5], [5, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[2, 2], [7, 7]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[7, 2], [2, 7]], \"height\": 0}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',17),(21,'jp_mountain','일본: 오에산','텐구가 지배하는 일본의 영산. 야마부시의 수행과 뇌신의 힘이 깃든 구름 위의 수련장.','⛩️',3,10,10,'stone','[{\"type\": \"stone\", \"coords\": [[4, 4], [5, 4], [4, 5], [5, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[2, 2], [7, 7]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[7, 2], [2, 7]], \"height\": 0}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',18),(22,'jp_temple','일본: 폐신사','오니 가면의 저주가 서린 일본 사찰. 천수관음 석상이 빙의되어 깨어나는 공포의 법당.','⛩️',5,10,10,'dark','[{\"type\": \"stone\", \"coords\": [[4, 4], [5, 4], [4, 5], [5, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[2, 2], [7, 7]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[7, 2], [2, 7]], \"height\": 0}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',19),(23,'jp_ocean','일본: 용궁','류진의 용궁으로 가는 깊은 바다. 갓파와 닌교, 후나유레이가 출몰하는 해저 세계.','🌊',4,10,10,'stone','[{\"type\": \"stone\", \"coords\": [[4, 4], [5, 4], [4, 5], [5, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[2, 2], [7, 7]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[7, 2], [2, 7]], \"height\": 0}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',20),(24,'jp_spirit','일본: 요괴의 길','시니가미가 지배하는 일본의 저승. 삼도천을 건너 엔마 대왕의 심판을 받는 명부의 길.','👺',6,10,10,'grass','[{\"type\": \"stone\", \"coords\": [[4, 4], [5, 4], [4, 5], [5, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[2, 2], [7, 7]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[7, 2], [2, 7]], \"height\": 0}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',21),(25,'cn_forest','중국: 산해경 숲','산해경의 마수가 서식하는 중국 신화의 숲. 호리정과 토지신, 태고의 괴물이 숨 쉬는 곳.','🌲',1,10,10,'grass','[{\"type\": \"stone\", \"coords\": [[4, 4], [5, 4], [4, 5], [5, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[2, 2], [7, 7]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[7, 2], [2, 7]], \"height\": 0}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',22),(26,'cn_mountain','중국: 곤륜산','곤륜산을 닮은 신선의 산. 도교 연단술과 무림 사찰, 하늘에 닿는 수행의 길.','🏔️',3,10,10,'stone','[{\"type\": \"stone\", \"coords\": [[4, 4], [5, 4], [4, 5], [5, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[2, 2], [7, 7]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[7, 2], [2, 7]], \"height\": 0}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',23),(27,'cn_temple','중국: 봉신대','사대천왕이 분노하는 중국 대사찰. 오백나한의 눈이 빛나고 진마탑이 흔들리는 성역.','🏯',5,10,10,'dark','[{\"type\": \"stone\", \"coords\": [[4, 4], [5, 4], [4, 5], [5, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[2, 2], [7, 7]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[7, 2], [2, 7]], \"height\": 0}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',24),(28,'cn_swamp','중국: 황천','강시와 고독(蠱毒)이 도사리는 저주의 늪. 부적과 주술이 난무하는 중국 공포의 습지.','💀',4,10,10,'stone','[{\"type\": \"stone\", \"coords\": [[4, 4], [5, 4], [4, 5], [5, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[2, 2], [7, 7]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[7, 2], [2, 7]], \"height\": 0}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',25),(29,'cn_spirit','중국: 요계','염라왕이 다스리는 중국의 지부(地府). 열 명의 명왕이 심판하는 사후 세계의 여정.','🐉',6,10,10,'grass','[{\"type\": \"stone\", \"coords\": [[4, 4], [5, 4], [4, 5], [5, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[2, 2], [7, 7]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[7, 2], [2, 7]], \"height\": 0}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 9}]',26);
