--
-- Table structure for table `monsters`
--

DROP TABLE IF EXISTS `monsters`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `monsters` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(50) NOT NULL,
  `dungeon_id` int NOT NULL,
  `icon` varchar(10) DEFAULT 0xF09F91B9,
  `hp` int NOT NULL,
  `attack` int NOT NULL,
  `defense` int DEFAULT '0',
  `move_range` int DEFAULT '3',
  `exp_reward` int DEFAULT '0',
  `gold_reward` int DEFAULT '0',
  `spawn_weight` int DEFAULT '10',
  `category_id` int DEFAULT NULL,
  `tier` int DEFAULT '1',
  `description` varchar(200) DEFAULT NULL,
  `country` varchar(20) DEFAULT 'korea',
  `ai_type` enum('aggressive','defensive','ranged','support','boss','coward') DEFAULT 'aggressive',
  `mp` int DEFAULT '0',
  `range_type` enum('melee','ranged','magic') DEFAULT 'melee',
  `element` enum('fire','water','earth','wind','neutral') DEFAULT 'neutral',
  `phys_attack` int DEFAULT '5',
  `phys_defense` int DEFAULT '3',
  `mag_attack` int DEFAULT '3',
  `mag_defense` int DEFAULT '2',
  `crit_rate` int DEFAULT '5',
  `evasion` int DEFAULT '3',
  PRIMARY KEY (`id`),
  KEY `dungeon_id` (`dungeon_id`),
  CONSTRAINT `monsters_ibfk_1` FOREIGN KEY (`dungeon_id`) REFERENCES `dungeons` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=282 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

