INSERT INTO `special_dungeon_types` VALUES (1,'tower','무한의 탑','끝없이 이어지는 시련의 탑. 매주 월요일에 진행도가 초기화됩니다.','srpg','weekly',10,1,'🗼','#a78bfa',1),(2,'elemental','정령의 시련','매일 바뀌는 속성의 정령과 싸워 정수와 결정을 획득하세요.','card','daily',15,1,'🌀','#22d3ee',2),(3,'boss_raid','보스 토벌전','강력한 보스에 도전하세요. 각 보스는 하루 1회 도전 가능합니다.','srpg','per_boss',20,2,'💀','#f97316',3);
