INSERT INTO `stage_groups` VALUES (1,'gojoseon','고조선','단군의 개국신화가 깃든 태초의 땅','🏔️','고조선 (BC 2333)',1,1,'#2d1b0e','korea','#4ade80'),(2,'samhan','삼한','마한, 변한, 진한 세 부족의 전장','⚔️','삼한시대',3,2,'#1a2e1a','korea','#60a5fa'),(3,'goguryeo','고구려','북방의 기마민족, 광개토대왕의 영토','🐎','삼국시대',5,3,'#2e1a1a','korea','#f87171'),(4,'baekje','백제','한강 유역의 문화 강국','🌸','삼국시대',7,4,'#1a1a2e','korea','#fbbf24'),(5,'silla','신라','화랑도의 정신으로 삼국을 통일','👑','삼국시대',9,5,'#2e2e1a','korea','#c084fc'),(6,'balhae','발해','해동성국, 고구려를 계승한 대제국','🦁','남북국시대',11,6,'#1a2e2e','korea','#2dd4bf'),(7,'goryeo','고려','불교 문화가 꽃피운 고려 왕조','📿','고려시대',13,7,'#2e1a2e','korea','#818cf8'),(8,'joseon','조선','유교의 이상향, 오백년 조선 왕조','📜','조선시대',16,8,'#0e1a2e','korea','#fb923c'),(9,'imjin','임진왜란','이순신 장군과 의병들의 구국 전쟁','🛡️','조선시대',19,9,'#2e0e0e','korea','#fb7185'),(10,'modern','근대','격변의 시대, 새로운 힘이 깨어난다','🔥','근대',22,10,'#1a0e2e','korea','#38bdf8'),(11,'jomon','조몬','토기 문화의 여명, 고대 일본의 시작','🏺','조몬시대 (BC 14000)',1,11,'#1a1e2e','japan','#8b9dc3'),(12,'yayoi','야요이','벼농사와 철기가 전래된 새 시대','🌾','야요이시대',3,12,'#1e2e1a','japan','#6bcb77'),(13,'yamato','야마토','일본 통일 왕조의 탄생','⛩️','야마토시대',5,13,'#2e1e1a','japan','#e8a87c'),(14,'nara','나라','불교와 율령 국가의 전성기','🏛️','나라시대',7,14,'#2e1a1e','japan','#d4a5a5'),(15,'heian','헤이안','귀족 문화가 꽃핀 우아한 시대','🌸','헤이안시대',9,15,'#1e1a2e','japan','#c9b1ff'),(16,'kamakura','가마쿠라','무사 정권의 시작, 사무라이의 시대','⚔️','가마쿠라시대',11,16,'#2e0e0e','japan','#ff6b6b'),(17,'muromachi','무로마치','남북조의 혼란과 무사 문화','🏯','무로마치시대',13,17,'#0e2e1e','japan','#48c9b0'),(18,'sengoku','전국시대','천하통일을 향한 영웅들의 전쟁','🔥','전국시대',16,18,'#2e0e1a','japan','#ff4757'),(19,'edo','에도','도쿠가와 막부의 태평성대','🎎','에도시대',19,19,'#1e1a0e','japan','#ffa502'),(20,'meiji','메이지','개혁과 근대화의 격변기','⚡','메이지시대',22,20,'#0e1a2e','japan','#70a1ff'),(21,'xia_shang','하·상','중화 문명의 여명, 청동기의 시대','🐉','하·상 (BC 2070)',1,21,'#2e1e0e','china','#d4a574'),(22,'zhou','주','봉건제와 제자백가의 시대','📜','주나라',3,22,'#0e1e2e','china','#7ec8e3'),(23,'qin','진','시황제의 천하통일 제국','🏰','진나라',5,23,'#2e0e0e','china','#c0392b'),(24,'han','한','유방의 대한제국 400년','🐎','한나라',7,24,'#2e1a0e','china','#e74c3c'),(25,'three_kingdoms','삼국','위·촉·오 영웅들의 시대','⚔️','삼국시대',9,25,'#1e2e0e','china','#f39c12'),(26,'tang','당','세계 최대 제국, 찬란한 문화','👑','당나라',11,26,'#2e1e1e','china','#e67e22'),(27,'song','송','문치주의와 과학 기술의 황금기','🧭','송나라',13,27,'#0e2e2e','china','#1abc9c'),(28,'yuan','원','몽골 대제국의 중원 정복','🏹','원나라',16,28,'#1a0e2e','china','#2c3e50'),(29,'ming','명','한족의 부흥, 정화의 대항해','⛵','명나라',19,29,'#2e0e1e','china','#e84393'),(30,'qing','청','만주족의 마지막 왕조','🐲','청나라',22,30,'#1e0e2e','china','#6c5ce7');
