DROP TABLE IF EXISTS `stage_levels`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `stage_levels` (
  `id` int NOT NULL AUTO_INCREMENT,
  `group_id` int NOT NULL,
  `stage_number` int NOT NULL,
  `name` varchar(100) NOT NULL,
  `description` varchar(300) DEFAULT NULL,
  `is_boss` tinyint(1) DEFAULT '0',
  `monster_count` int DEFAULT '3',
  `monster_level_min` int DEFAULT '1',
  `monster_level_max` int DEFAULT '3',
  `reward_exp` int DEFAULT '100',
  `reward_gold` int DEFAULT '50',
  `dungeon_key` varchar(50) DEFAULT NULL,
  `map_width` int DEFAULT '10',
  `map_height` int DEFAULT '10',
  `base_tile_type` varchar(20) DEFAULT 'grass',
  `tile_overrides` json DEFAULT NULL,
  `player_spawns` json DEFAULT NULL,
  `monster_spawns` json DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_group_stage` (`group_id`,`stage_number`),
  CONSTRAINT `stage_levels_ibfk_1` FOREIGN KEY (`group_id`) REFERENCES `stage_groups` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=354 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
