LOCK TABLES `stage_levels` WRITE;
/*!40000 ALTER TABLE `stage_levels` DISABLE KEYS */;
INSERT INTO `stage_levels` VALUES (1,1,1,'아사달 평원','태초의 빛이 비추는 아사달 평원. 단군왕검이 처음 도읍을 세운 이 광활한 들판에는 아직도 개국의 기운이 서려 있다. 약한 야수들이 배회하지만 방심하면 위험하다.',0,2,1,2,80,40,'kr_forest',8,8,'grass','[{\"type\": \"water\", \"coords\": [[4, 1], [4, 2], [4, 3], [5, 1], [5, 2], [5, 3], [6, 1], [6, 2], [6, 3]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[4, 2], [4, 3], [4, 4], [5, 2], [5, 3], [5, 4], [6, 2], [6, 3], [6, 4]], \"height\": 2}, {\"type\": \"dark\", \"coords\": [[4, 5], [4, 6], [4, 7], [5, 5], [5, 6], [5, 7], [6, 5], [6, 6], [6, 7]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}]','[{\"x\": 7, \"z\": 7}, {\"x\": 6, \"z\": 7}]'),(2,1,2,'신단수 아래','하늘과 땅을 잇는 신단수(神檀樹) 아래. 환웅이 처음 땅에 내려온 이 신성한 장소에서 자연의 수호자들이 침입자를 경계하고 있다.',0,2,1,2,90,45,'kr_forest',8,8,'grass','[{\"type\": \"water\", \"coords\": [[4, 4], [4, 5], [5, 4], [5, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[1, 2]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[5, 4], [5, 5], [6, 4], [6, 5]], \"height\": 2}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}]','[{\"x\": 7, \"z\": 7}, {\"x\": 6, \"z\": 7}]'),(3,1,3,'환웅의 시련','환웅이 인간에게 내린 세 가지 시련의 장. 풍백, 우사, 운사의 힘이 소용돌이치는 이곳에서 살아남아야 진정한 전사로 인정받을 수 있다.',0,3,1,3,100,50,'kr_forest',9,9,'grass','[{\"type\": \"stone\", \"coords\": [[7, 3], [7, 4], [8, 3], [8, 4]], \"height\": 3}, {\"type\": \"grass\", \"coords\": [[6, 7], [6, 8], [7, 7], [7, 8], [8, 7], [8, 8]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[7, 2]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]'),(4,1,4,'쑥과 마늘의 동굴','곰과 호랑이가 인간이 되고자 백일간 수행한 동굴. 어둠 속에서 울리는 울음소리와 함께 동굴 깊은 곳의 마물들이 깨어나고 있다.',0,3,2,3,110,55,'kr_forest',9,8,'stone','[{\"type\": \"dirt\", \"coords\": [[5, 1], [5, 2], [6, 1], [6, 2]], \"height\": 3}, {\"type\": \"grass\", \"coords\": [[3, 3]], \"height\": 2}, {\"type\": \"dark\", \"coords\": [[2, 6]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 8, \"z\": 7}, {\"x\": 7, \"z\": 7}, {\"x\": 8, \"z\": 6}]'),(5,1,5,'풍백의 언덕','바람을 다스리는 신 풍백이 머물던 언덕. 거센 바람이 끊임없이 불어오는 이곳에서는 바람에 실려 온 정령들과 마주하게 된다.',0,3,2,4,120,60,'kr_forest',10,8,'grass','[{\"type\": \"stone\", \"coords\": [[7, 1], [7, 2], [8, 1], [8, 2]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[3, 3], [3, 4], [4, 3], [4, 4]], \"height\": 3}, {\"type\": \"dark\", \"coords\": [[4, 4], [4, 5], [4, 6], [5, 4], [5, 5], [5, 6], [6, 4], [6, 5], [6, 6]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 9, \"z\": 7}, {\"x\": 8, \"z\": 7}, {\"x\": 9, \"z\": 6}]'),(6,1,6,'우사의 늪','비의 신 우사가 다스리는 안개 자욱한 늪지대. 발이 빠지는 질퍽한 땅 위로 수생 마물들이 도사리고 있다. 지형을 이용한 전략이 필요하다.',0,3,2,4,130,65,'kr_forest',10,9,'grass','[{\"type\": \"grass\", \"coords\": [[1, 3]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[5, 7], [5, 8], [6, 7], [6, 8], [7, 7], [7, 8]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[4, 4]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 7}]'),(7,1,7,'운사의 산길','구름의 신 운사가 자욱한 안개로 감춘 비밀의 산길. 앞이 보이지 않는 험로를 따라가면 강력한 산짐승들이 기다리고 있다.',0,4,3,5,140,70,'kr_forest',10,10,'grass','[{\"type\": \"water\", \"coords\": [[3, 7], [3, 8], [3, 9], [4, 7], [4, 8], [4, 9], [5, 7], [5, 8], [5, 9]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[7, 4], [7, 5], [8, 4], [8, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[4, 5], [4, 6], [5, 5], [5, 6]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(8,1,8,'비파산 전투','고조선의 서쪽 전략 요충지 비파산. 견고한 석벽과 험한 지형 사이로 적들이 매복하고 있다. 높은 곳을 선점하는 것이 승리의 열쇠다.',0,4,3,5,155,75,'kr_forest',10,10,'stone','[{\"type\": \"water\", \"coords\": [[3, 3], [3, 4], [4, 3], [4, 4]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[2, 4], [2, 5], [3, 4], [3, 5]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[6, 3], [6, 4], [7, 3], [7, 4]], \"height\": 2}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(9,1,9,'왕검성 외곽','왕검성으로 통하는 마지막 관문. 수도를 지키려는 수호자들이 총력을 기울여 방어하고 있다. 이곳을 돌파해야 최종 시련에 도전할 수 있다.',0,4,3,5,170,80,'kr_forest',10,10,'grass','[{\"type\": \"water\", \"coords\": [[3, 7], [3, 8], [4, 7], [4, 8]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[6, 4], [6, 5], [6, 6], [7, 4], [7, 5], [7, 6], [8, 4], [8, 5], [8, 6]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[7, 2]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(10,1,10,'단군의 시련','고조선의 개국자 단군왕검이 후대 전사들을 위해 남긴 최후의 시험장. 신성한 기운이 가득한 이 전장에서 역사의 첫 장을 장식할 영웅이 탄생한다.',1,5,4,6,250,120,'kr_forest',12,12,'grass','[{\"type\": \"water\", \"coords\": [[10, 9]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[7, 7], [7, 8], [7, 9], [8, 7], [8, 8], [8, 9], [9, 7], [9, 8], [9, 9]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[9, 9]], \"height\": 1}, {\"type\": \"stone\", \"coords\": [[6, 6], [5, 6], [6, 5], [5, 5]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 11, \"z\": 11}, {\"x\": 10, \"z\": 11}, {\"x\": 11, \"z\": 10}, {\"x\": 10, \"z\": 10}, {\"x\": 11, \"z\": 9}]'),(11,2,1,'마한 촌락','마한 78개 소국 중 하나의 작은 촌락. 초가지붕 아래 평화로워 보이지만, 밤이 되면 주변 산에서 내려온 마물들이 마을을 위협한다.',0,2,3,4,100,50,'kr_forest',8,8,'grass','[{\"type\": \"water\", \"coords\": [[4, 1], [4, 2], [4, 3], [5, 1], [5, 2], [5, 3], [6, 1], [6, 2], [6, 3]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[4, 2], [4, 3], [4, 4], [5, 2], [5, 3], [5, 4], [6, 2], [6, 3], [6, 4]], \"height\": 2}, {\"type\": \"dark\", \"coords\": [[4, 5], [4, 6], [4, 7], [5, 5], [5, 6], [5, 7], [6, 5], [6, 6], [6, 7]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}]','[{\"x\": 7, \"z\": 7}, {\"x\": 6, \"z\": 7}]'),(12,2,2,'변한 대장간','삼한 시대 철기문화의 중심지인 변한의 대장간. 붉게 달궈진 쇳물 사이로 불의 정령들이 출몰하며, 강인한 전사만이 이 열기를 견딜 수 있다.',0,3,3,5,110,55,'kr_forest',8,9,'stone','[{\"type\": \"dirt\", \"coords\": [[5, 4], [5, 5], [6, 4], [6, 5]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[5, 6], [5, 7], [6, 6], [6, 7]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[4, 5]], \"height\": 2}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 7, \"z\": 8}, {\"x\": 6, \"z\": 8}, {\"x\": 7, \"z\": 7}]'),(13,2,3,'진한 의례장','진한 부족이 하늘에 제사를 올리던 신성한 의례장. 영적인 기운이 가득한 이곳에서는 고대의 제물들이 되살아나 침입자를 막아선다.',0,3,4,5,120,60,'kr_forest',9,9,'grass','[{\"type\": \"stone\", \"coords\": [[7, 3], [7, 4], [8, 3], [8, 4]], \"height\": 3}, {\"type\": \"grass\", \"coords\": [[6, 7], [6, 8], [7, 7], [7, 8], [8, 7], [8, 8]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[7, 2]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]'),(14,2,4,'소도','천군(天君)이 다스리는 소도(蘇塗). 솟대가 세워진 이 신성불가침의 영역에 들어선 순간, 하늘의 수호신들이 시련을 내린다.',0,3,4,6,130,65,'kr_forest',10,9,'grass','[{\"type\": \"grass\", \"coords\": [[8, 3], [8, 4], [9, 3], [9, 4]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[6, 7], [6, 8], [7, 7], [7, 8], [8, 7], [8, 8]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[2, 6], [2, 7], [2, 8], [3, 6], [3, 7], [3, 8], [4, 6], [4, 7], [4, 8]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}, {\"x\": 9, \"z\": 7}]'),(15,2,5,'두레 전장','삼한의 부족들이 연합하여 싸운 대규모 전쟁터. 두레의 정신으로 뭉친 전사들의 함성이 울려 퍼지는 광활한 전장이다.',0,3,4,6,140,70,'kr_forest',10,10,'grass','[{\"type\": \"water\", \"coords\": [[2, 6]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[8, 4], [8, 5], [9, 4], [9, 5]], \"height\": 2}, {\"type\": \"dark\", \"coords\": [[2, 7]], \"height\": 2}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}]'),(16,2,6,'철의 계곡','변한의 깊은 철광산 계곡. 쇳덩어리와 광석이 빛나는 어두운 갱도 속에서 지하의 마물들이 광맥을 지키고 있다.',0,4,5,7,155,75,'kr_forest',10,10,'stone','[{\"type\": \"water\", \"coords\": [[3, 2], [3, 3], [3, 4], [4, 2], [4, 3], [4, 4], [5, 2], [5, 3], [5, 4]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[3, 4], [3, 5], [4, 4], [4, 5]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[3, 6], [3, 7], [3, 8], [4, 6], [4, 7], [4, 8], [5, 6], [5, 7], [5, 8]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(17,2,7,'제천 의식장','삼한의 제천 행사 영고, 동맹, 무천이 열리는 의식의 장. 하늘에 기원하는 제사 중 깨어난 고대의 영혼들과 맞서 싸워야 한다.',0,4,5,7,170,80,'kr_forest',10,10,'grass','[{\"type\": \"water\", \"coords\": [[3, 7], [3, 8], [3, 9], [4, 7], [4, 8], [4, 9], [5, 7], [5, 8], [5, 9]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[7, 4], [7, 5], [8, 4], [8, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[4, 5], [4, 6], [5, 5], [5, 6]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(18,2,8,'목지국 성벽','마한 연맹의 수도 목지국을 둘러싼 견고한 성벽. 수도를 지키려는 정예 수비대와 성벽에 깃든 수호 영혼들이 방어선을 형성한다.',0,4,5,8,185,90,'kr_forest',10,10,'stone','[{\"type\": \"water\", \"coords\": [[3, 3], [3, 4], [4, 3], [4, 4]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[2, 4], [2, 5], [3, 4], [3, 5]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[6, 3], [6, 4], [7, 3], [7, 4]], \"height\": 2}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(19,2,9,'구야국 항구','가야의 전신인 구야국의 번화한 항구. 해상 무역으로 부를 쌓은 이 도시를 노리는 해적과 수생 마물들이 포구 주변에 출몰한다.',0,4,6,8,200,95,'kr_forest',10,10,'stone','[{\"type\": \"water\", \"coords\": [[3, 7], [3, 8], [4, 7], [4, 8]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[6, 4], [6, 5], [6, 6], [7, 4], [7, 5], [7, 6], [8, 4], [8, 5], [8, 6]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[7, 2]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(20,2,10,'삼한 왕의 결전','마한, 변한, 진한 세 부족의 운명을 건 최후의 대결전. 각 부족의 최강 전사들과 고대의 수호신이 총출동하는 역사적 전투의 장이다.',1,5,6,9,300,150,'kr_forest',12,12,'grass','[{\"type\": \"water\", \"coords\": [[10, 9]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[7, 7], [7, 8], [7, 9], [8, 7], [8, 8], [8, 9], [9, 7], [9, 8], [9, 9]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[9, 9]], \"height\": 1}, {\"type\": \"stone\", \"coords\": [[6, 6], [5, 6], [6, 5], [5, 5]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 11, \"z\": 11}, {\"x\": 10, \"z\": 11}, {\"x\": 11, \"z\": 10}, {\"x\": 10, \"z\": 10}, {\"x\": 11, \"z\": 9}]'),(21,3,1,'졸본성','고구려의 시조 주몽이 세운 첫 번째 수도 졸본성. 건국의 기상이 서린 이 산성에서 북방의 맹수들과 첫 전투가 시작된다.',0,3,5,7,140,70,'kr_mountain',9,9,'stone','[{\"type\": \"stone\", \"coords\": [[6, 3], [6, 4], [6, 5], [7, 3], [7, 4], [7, 5], [8, 3], [8, 4], [8, 5]], \"height\": 3}, {\"type\": \"grass\", \"coords\": [[6, 7], [6, 8], [7, 7], [7, 8]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[5, 4], [5, 5], [6, 4], [6, 5]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]'),(22,3,2,'국내성 외곽','유리왕이 천도한 두 번째 수도 국내성의 외곽 방어 진지. 주변 부족들의 끊임없는 침공에 맞서 성을 지켜내야 한다.',0,3,5,7,150,75,'kr_mountain',9,9,'stone','[{\"type\": \"stone\", \"coords\": [[7, 7], [7, 8], [8, 7], [8, 8]], \"height\": 3}, {\"type\": \"dirt\", \"coords\": [[3, 7], [3, 8], [4, 7], [4, 8]], \"height\": 2}, {\"type\": \"dark\", \"coords\": [[6, 3]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]'),(23,3,3,'환도산성','천혜의 요새 환도산성. 험준한 산세를 이용한 난공불락의 산성이지만, 산 속의 마물들도 함께 상대해야 하는 험난한 전투가 기다린다.',0,3,6,8,165,80,'kr_mountain',10,10,'stone','[{\"type\": \"water\", \"coords\": [[2, 6], [2, 7], [3, 6], [3, 7]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[8, 4]], \"height\": 2}, {\"type\": \"dark\", \"coords\": [[7, 2], [7, 3], [7, 4], [8, 2], [8, 3], [8, 4], [9, 2], [9, 3], [9, 4]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}]'),(24,3,4,'요동 벌판','만주 벌판을 호령하던 고구려 기마대가 누빈 광활한 요동 벌판. 끝없이 펼쳐진 초원에서 기동력이 승패를 가른다.',0,3,6,8,175,85,'kr_mountain',10,10,'grass','[{\"type\": \"water\", \"coords\": [[2, 2]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[4, 4], [4, 5], [5, 4], [5, 5]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[8, 8], [8, 9], [9, 8], [9, 9]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}]'),(25,3,5,'살수대첩','수나라 113만 대군을 30만으로 격파한 전설의 전장. 을지문덕 장군의 지략이 깃든 살수에서 적을 유인하고 섬멸하라.',0,4,7,9,190,90,'kr_mountain',10,10,'grass','[{\"type\": \"water\", \"coords\": [[2, 6]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[8, 4], [8, 5], [9, 4], [9, 5]], \"height\": 2}, {\"type\": \"dark\", \"coords\": [[2, 7]], \"height\": 2}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(26,3,6,'안시성','당 태종의 20만 대군을 88일간 막아낸 철벽 안시성. 성주 양만춘의 불굴의 의지가 서린 이곳에서 압도적인 적과 맞서야 한다.',0,4,7,9,205,95,'kr_mountain',10,10,'stone','[{\"type\": \"water\", \"coords\": [[3, 2], [3, 3], [3, 4], [4, 2], [4, 3], [4, 4], [5, 2], [5, 3], [5, 4]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[3, 4], [3, 5], [4, 4], [4, 5]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[3, 6], [3, 7], [3, 8], [4, 6], [4, 7], [4, 8], [5, 6], [5, 7], [5, 8]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(27,3,7,'평양성 내성','고구려 마지막 수도 평양성의 내성. 최후의 방어전이 벌어지는 이곳에서 왕성을 사수하기 위한 결사적인 전투가 펼쳐진다.',0,4,7,10,220,100,'kr_mountain',10,10,'stone','[{\"type\": \"water\", \"coords\": [[3, 7], [3, 8], [3, 9], [4, 7], [4, 8], [4, 9], [5, 7], [5, 8], [5, 9]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[7, 4], [7, 5], [8, 4], [8, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[4, 5], [4, 6], [5, 5], [5, 6]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(28,3,8,'광개토대왕릉','정복왕 광개토대왕의 능 주변. 대왕의 위엄과 기운이 서려 있어 강력한 수호 영혼들이 무덤을 지키고 있다.',0,4,8,10,235,110,'kr_mountain',10,10,'stone','[{\"type\": \"water\", \"coords\": [[3, 3], [3, 4], [4, 3], [4, 4]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[2, 4], [2, 5], [3, 4], [3, 5]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[6, 3], [6, 4], [7, 3], [7, 4]], \"height\": 2}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(29,3,9,'장수왕의 남진','장수왕의 남하 정책으로 한강 유역까지 진격하는 대진격전. 남쪽으로 영토를 넓히며 적의 저항을 물리쳐야 한다.',0,4,8,11,250,115,'kr_mountain',10,10,'grass','[{\"type\": \"water\", \"coords\": [[3, 7], [3, 8], [4, 7], [4, 8]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[6, 4], [6, 5], [6, 6], [7, 4], [7, 5], [7, 6], [8, 4], [8, 5], [8, 6]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[7, 2]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(30,3,10,'을지문덕의 결전','살수에서 을지문덕 장군이 펼치는 마지막 결전. 적을 깊숙이 유인한 뒤 물길을 터뜨려 섬멸하는 역사적 전투를 재현한다.',0,5,8,11,280,125,'kr_mountain',12,10,'grass','[{\"type\": \"stone\", \"coords\": [[6, 2], [6, 3], [6, 4], [7, 2], [7, 3], [7, 4], [8, 2], [8, 3], [8, 4]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[1, 5], [1, 6], [1, 7], [2, 5], [2, 6], [2, 7], [3, 5], [3, 6], [3, 7]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[2, 5], [2, 6], [2, 7], [3, 5], [3, 6], [3, 7], [4, 5], [4, 6], [4, 7]], \"height\": 2}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 11, \"z\": 9}, {\"x\": 10, \"z\": 9}, {\"x\": 11, \"z\": 8}, {\"x\": 10, \"z\": 8}, {\"x\": 11, \"z\": 7}]'),(31,3,11,'연개소문의 시련','연개소문의 철권통치와 야망이 깃든 전장. 독재자의 군대는 강력하지만, 그 야망만큼이나 위험한 마물들도 깨어나고 있다.',0,5,9,12,310,135,'kr_mountain',12,10,'stone','[{\"type\": \"stone\", \"coords\": [[6, 6], [6, 7], [7, 6], [7, 7]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[5, 5], [5, 6], [5, 7], [6, 5], [6, 6], [6, 7], [7, 5], [7, 6], [7, 7]], \"height\": 3}, {\"type\": \"stone\", \"coords\": [[4, 4], [4, 5], [4, 6], [5, 4], [5, 5], [5, 6], [6, 4], [6, 5], [6, 6]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 11, \"z\": 9}, {\"x\": 10, \"z\": 9}, {\"x\": 11, \"z\": 8}, {\"x\": 10, \"z\": 8}, {\"x\": 11, \"z\": 7}]'),(32,3,12,'고구려 최후의 전투','700년 대제국 고구려 최후의 날. 내부 분열과 외세의 공격 속에서 제국의 마지막 빛을 지키기 위한 처절한 사투가 벌어진다.',1,6,9,13,400,200,'kr_mountain',12,12,'stone','[{\"type\": \"water\", \"coords\": [[1, 9], [1, 10], [1, 11], [2, 9], [2, 10], [2, 11], [3, 9], [3, 10], [3, 11]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[6, 7]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[2, 5], [2, 6], [3, 5], [3, 6]], \"height\": 3}, {\"type\": \"stone\", \"coords\": [[6, 6], [5, 6], [6, 5], [5, 5]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 11, \"z\": 11}, {\"x\": 10, \"z\": 11}, {\"x\": 11, \"z\": 10}, {\"x\": 10, \"z\": 10}, {\"x\": 11, \"z\": 9}, {\"x\": 10, \"z\": 9}]'),(33,4,1,'위례성','온조가 한강 유역에 세운 백제의 첫 도읍 위례성. 강변의 비옥한 평야에서 새 왕국의 기초를 닦으며 주변의 위협을 물리쳐야 한다.',0,3,7,9,170,85,'kr_swamp',9,9,'grass','[{\"type\": \"stone\", \"coords\": [[6, 3], [6, 4], [6, 5], [7, 3], [7, 4], [7, 5], [8, 3], [8, 4], [8, 5]], \"height\": 3}, {\"type\": \"grass\", \"coords\": [[6, 7], [6, 8], [7, 7], [7, 8]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[5, 4], [5, 5], [6, 4], [6, 5]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]'),(34,4,2,'한산 기슭','새로운 터전을 마련한 한산 기슭의 방어전. 산 아래로 밀려오는 마물들의 공격을 막아내며 영토를 확보해야 한다.',0,3,7,9,180,90,'kr_swamp',9,9,'grass','[{\"type\": \"stone\", \"coords\": [[7, 7], [7, 8], [8, 7], [8, 8]], \"height\": 3}, {\"type\": \"dirt\", \"coords\": [[3, 7], [3, 8], [4, 7], [4, 8]], \"height\": 2}, {\"type\": \"dark\", \"coords\": [[6, 3]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]'),(35,4,3,'웅진 도하','금강을 건너 웅진으로 천도하는 격류의 전투. 강물 위에서 벌어지는 위험천만한 도하 작전에서 적의 방해를 뚫고 나아가라.',0,3,8,10,195,95,'kr_swamp',10,10,'grass','[{\"type\": \"water\", \"coords\": [[2, 6], [2, 7], [3, 6], [3, 7]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[8, 4]], \"height\": 2}, {\"type\": \"dark\", \"coords\": [[7, 2], [7, 3], [7, 4], [8, 2], [8, 3], [8, 4], [9, 2], [9, 3], [9, 4]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}]'),(36,4,4,'사비성 공방','백제의 마지막 수도 사비성에서 벌어지는 치열한 공방전. 성벽 위에서 쏟아지는 화살과 마법 공격 속에서 성을 지켜내야 한다.',0,3,8,10,205,100,'kr_swamp',10,10,'grass','[{\"type\": \"water\", \"coords\": [[2, 2]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[4, 4], [4, 5], [5, 4], [5, 5]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[8, 8], [8, 9], [9, 8], [9, 9]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}]'),(37,4,5,'무령왕릉','백제 25대 무령왕의 능. 정교한 벽돌무덤 속에 잠든 왕의 수호령들이 깨어나 침입자를 시험한다. 백제 문화의 정수를 느낄 수 있는 곳이다.',0,4,8,11,220,105,'kr_swamp',10,10,'stone','[{\"type\": \"water\", \"coords\": [[2, 6]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[8, 4], [8, 5], [9, 4], [9, 5]], \"height\": 2}, {\"type\": \"dark\", \"coords\": [[2, 7]], \"height\": 2}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(38,4,6,'미륵사 터','동양 최대 사찰이었던 미륵사의 폐허. 거대한 석탑 사이로 깃든 불교의 수호신과 마물들이 뒤섞여 혼돈의 전장을 만든다.',0,4,9,11,235,110,'kr_swamp',10,10,'stone','[{\"type\": \"water\", \"coords\": [[3, 2], [3, 3], [3, 4], [4, 2], [4, 3], [4, 4], [5, 2], [5, 3], [5, 4]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[3, 4], [3, 5], [4, 4], [4, 5]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[3, 6], [3, 7], [3, 8], [4, 6], [4, 7], [4, 8], [5, 6], [5, 7], [5, 8]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(39,4,7,'백마강 전투','삼천 궁녀의 전설이 서린 백마강가. 낙화암의 슬픈 역사가 깃든 이곳에서 강물에서 솟아오른 원혼들과 맞서 싸워야 한다.',0,4,9,12,250,120,'kr_swamp',10,10,'grass','[{\"type\": \"water\", \"coords\": [[3, 7], [3, 8], [3, 9], [4, 7], [4, 8], [4, 9], [5, 7], [5, 8], [5, 9]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[7, 4], [7, 5], [8, 4], [8, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[4, 5], [4, 6], [5, 5], [5, 6]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(40,4,8,'관산성','성왕이 전사한 비극의 전장 관산성. 왕의 원통한 기운이 서려 있어 강력한 원령들이 출몰하는 위험한 곳이다.',0,4,9,12,265,125,'kr_swamp',10,10,'stone','[{\"type\": \"water\", \"coords\": [[3, 3], [3, 4], [4, 3], [4, 4]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[2, 4], [2, 5], [3, 4], [3, 5]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[6, 3], [6, 4], [7, 3], [7, 4]], \"height\": 2}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(41,4,9,'황산벌 전야','계백 장군이 결사대 5천을 이끌고 최후의 전투를 벌인 황산벌. 죽음을 각오한 전사들의 기백이 서린 비장한 전장이다.',0,5,10,13,280,135,'kr_swamp',12,10,'grass','[{\"type\": \"stone\", \"coords\": [[5, 6], [5, 7], [5, 8], [6, 6], [6, 7], [6, 8], [7, 6], [7, 7], [7, 8]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[6, 5], [6, 6], [6, 7], [7, 5], [7, 6], [7, 7], [8, 5], [8, 6], [8, 7]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[10, 6]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 11, \"z\": 9}, {\"x\": 10, \"z\": 9}, {\"x\": 11, \"z\": 8}, {\"x\": 10, \"z\": 8}, {\"x\": 11, \"z\": 7}]'),(42,4,10,'계백 장군의 결전','백제 최후의 충신 계백 장군과의 결전. 처자식까지 스스로 베어 물러설 곳 없는 장군의 결의와 맞서는 최종 보스전이다.',1,5,10,14,420,210,'kr_swamp',12,12,'grass','[{\"type\": \"water\", \"coords\": [[10, 9]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[7, 7], [7, 8], [7, 9], [8, 7], [8, 8], [8, 9], [9, 7], [9, 8], [9, 9]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[9, 9]], \"height\": 1}, {\"type\": \"stone\", \"coords\": [[6, 6], [5, 6], [6, 5], [5, 5]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 11, \"z\": 11}, {\"x\": 10, \"z\": 11}, {\"x\": 11, \"z\": 10}, {\"x\": 10, \"z\": 10}, {\"x\": 11, \"z\": 9}]'),(43,5,1,'경주 남산','신라의 성스러운 산 경주 남산. 수많은 불상과 탑이 세워진 이 영험한 산에서 불교의 수호신들이 침입자를 시험한다.',0,3,9,11,200,100,'kr_temple',9,9,'grass','[{\"type\": \"stone\", \"coords\": [[6, 3], [6, 4], [6, 5], [7, 3], [7, 4], [7, 5], [8, 3], [8, 4], [8, 5]], \"height\": 3}, {\"type\": \"grass\", \"coords\": [[6, 7], [6, 8], [7, 7], [7, 8]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[5, 4], [5, 5], [6, 4], [6, 5]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]'),(44,5,2,'화랑 수련장','화랑도가 심신을 수련하던 훈련장. 세속오계의 정신 아래 단련된 화랑들의 영혼이 깃들어 있어, 진정한 전사만이 통과할 수 있다.',0,3,9,11,210,105,'kr_temple',9,9,'grass','[{\"type\": \"stone\", \"coords\": [[7, 7], [7, 8], [8, 7], [8, 8]], \"height\": 3}, {\"type\": \"dirt\", \"coords\": [[3, 7], [3, 8], [4, 7], [4, 8]], \"height\": 2}, {\"type\": \"dark\", \"coords\": [[6, 3]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 8, \"z\": 8}, {\"x\": 7, \"z\": 8}, {\"x\": 8, \"z\": 7}]'),(45,5,3,'첨성대 주변','동양 최고(最古)의 천문대 첨성대 주변. 별의 기운이 모이는 이 신비로운 장소에서 천체의 힘을 품은 마물들이 출현한다.',0,3,10,12,225,110,'kr_temple',10,10,'stone','[{\"type\": \"water\", \"coords\": [[2, 6], [2, 7], [3, 6], [3, 7]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[8, 4]], \"height\": 2}, {\"type\": \"dark\", \"coords\": [[7, 2], [7, 3], [7, 4], [8, 2], [8, 3], [8, 4], [9, 2], [9, 3], [9, 4]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}]'),(46,5,4,'불국사 경내','부처의 나라를 현세에 구현한 불국사 경내. 청운교와 백운교를 건너면 극락의 수호자들이 기다리는 환상적인 전장이 펼쳐진다.',0,3,10,12,235,115,'kr_temple',10,10,'stone','[{\"type\": \"water\", \"coords\": [[2, 2]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[4, 4], [4, 5], [5, 4], [5, 5]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[8, 8], [8, 9], [9, 8], [9, 9]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}]'),(47,5,5,'석굴암 석실','동해의 일출을 바라보는 석굴암의 신비로운 석실. 본존불의 자비로운 기운과 함께 석굴 속 깊은 곳의 암흑 마물들이 공존하는 곳이다.',0,4,10,13,250,120,'kr_temple',10,10,'stone','[{\"type\": \"water\", \"coords\": [[2, 6]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[8, 4], [8, 5], [9, 4], [9, 5]], \"height\": 2}, {\"type\": \"dark\", \"coords\": [[2, 7]], \"height\": 2}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(48,5,6,'대릉원','신라 왕들이 잠든 대릉원의 고분군. 황금 보관과 유물들을 지키는 고대 왕들의 수호령이 무덤 사이를 떠돌고 있다.',0,4,11,13,265,130,'kr_temple',10,10,'grass','[{\"type\": \"water\", \"coords\": [[3, 2], [3, 3], [3, 4], [4, 2], [4, 3], [4, 4], [5, 2], [5, 3], [5, 4]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[3, 4], [3, 5], [4, 4], [4, 5]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[3, 6], [3, 7], [3, 8], [4, 6], [4, 7], [4, 8], [5, 6], [5, 7], [5, 8]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(49,5,7,'김유신의 출전','삼국통일의 영웅 김유신 장군과 함께하는 출정. 장군의 명검 기운이 서린 전장에서 적군을 무찔러야 한다.',0,4,11,14,280,135,'kr_temple',10,10,'grass','[{\"type\": \"water\", \"coords\": [[3, 7], [3, 8], [3, 9], [4, 7], [4, 8], [4, 9], [5, 7], [5, 8], [5, 9]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[7, 4], [7, 5], [8, 4], [8, 5]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[4, 5], [4, 6], [5, 5], [5, 6]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(50,5,8,'매소성 전투','675년 당군 20만을 격파한 매소성 결전지. 나당전쟁의 승리를 결정지은 이 역사적 전장에서 외세의 침략을 물리쳐라.',0,4,11,14,295,140,'kr_temple',10,10,'grass','[{\"type\": \"water\", \"coords\": [[3, 3], [3, 4], [4, 3], [4, 4]], \"height\": 2}, {\"type\": \"stone\", \"coords\": [[2, 4], [2, 5], [3, 4], [3, 5]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[6, 3], [6, 4], [7, 3], [7, 4]], \"height\": 2}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}, {\"x\": 8, \"z\": 8}]'),(51,5,9,'기벌포 해전','신라 수군이 당나라 함대를 격파한 기벌포 해전. 파도 위에서 벌어지는 해상 전투에서 적 함대를 침몰시켜야 한다.',0,5,12,15,310,150,'kr_temple',12,10,'stone','[{\"type\": \"stone\", \"coords\": [[5, 6], [5, 7], [5, 8], [6, 6], [6, 7], [6, 8], [7, 6], [7, 7], [7, 8]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[6, 5], [6, 6], [6, 7], [7, 5], [7, 6], [7, 7], [8, 5], [8, 6], [8, 7]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[10, 6]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 11, \"z\": 9}, {\"x\": 10, \"z\": 9}, {\"x\": 11, \"z\": 8}, {\"x\": 10, \"z\": 8}, {\"x\": 11, \"z\": 7}]'),(52,5,10,'비담의 난','선덕여왕에 반기를 든 비담의 난. 왕궁을 향해 진격하는 반란군과 여왕을 지키려는 충신들의 혈전이 펼쳐진다.',0,5,12,15,330,155,'kr_temple',12,10,'stone','[{\"type\": \"stone\", \"coords\": [[6, 2], [6, 3], [6, 4], [7, 2], [7, 3], [7, 4], [8, 2], [8, 3], [8, 4]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[1, 5], [1, 6], [1, 7], [2, 5], [2, 6], [2, 7], [3, 5], [3, 6], [3, 7]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[2, 5], [2, 6], [2, 7], [3, 5], [3, 6], [3, 7], [4, 5], [4, 6], [4, 7]], \"height\": 2}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 11, \"z\": 9}, {\"x\": 10, \"z\": 9}, {\"x\": 11, \"z\": 8}, {\"x\": 10, \"z\": 8}, {\"x\": 11, \"z\": 7}]'),(53,5,11,'문무왕