\": [[5, 2], [5, 3], [6, 2], [6, 3]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 11, \"z\": 9}, {\"x\": 10, \"z\": 9}, {\"x\": 11, \"z\": 8}, {\"x\": 10, \"z\": 8}, {\"x\": 11, \"z\": 7}]'),(90,8,13,'경회루 결전','경복궁 연못 위에 세워진 경회루에서의 장엄한 결전. 물 위에 떠있는 누각에서 벌어지는 환상적인 전투의 무대다.',0,5,20,23,570,280,'kr_temple',12,10,'stone','[{\"type\": \"stone\", \"coords\": [[6, 6]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[4, 5]], \"height\": 3}, {\"type\": \"stone\", \"coords\": [[7, 1]], \"height\": 2}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 11, \"z\": 9}, {\"x\": 10, \"z\": 9}, {\"x\": 11, \"z\": 8}, {\"x\": 10, \"z\": 8}, {\"x\": 11, \"z\": 7}]'),(91,8,14,'세종대왕의 시련','한글 창제, 측우기, 해시계 등 수많은 업적을 남긴 세종대왕이 후대를 위해 남긴 최후의 시험. 성군의 지혜와 힘을 모두 상대해야 한다.',1,6,21,25,750,375,'kr_temple',14,12,'stone','[{\"type\": \"stone\", \"coords\": [[3, 8]], \"height\": 2}, {\"type\": \"grass\", \"coords\": [[4, 8], [4, 9], [5, 8], [5, 9]], \"height\": 2}, {\"type\": \"water\", \"coords\": [[8, 7]], \"height\": 3}, {\"type\": \"stone\", \"coords\": [[7, 6], [6, 6], [7, 5], [6, 5]], \"height\": 3}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}, {\"x\": 1, \"z\": 1}]','[{\"x\": 13, \"z\": 11}, {\"x\": 12, \"z\": 11}, {\"x\": 13, \"z\": 10}, {\"x\": 12, \"z\": 10}, {\"x\": 13, \"z\": 9}, {\"x\": 12, \"z\": 9}]'),(92,9,1,'부산진 상륙','1592년 4월, 일본군이 처음 상륙한 부산진. 바다에서 밀려오는 대군에 맞서 해안을 사수하는 치열한 방어전이 시작된다.',0,3,19,21,420,210,'kr_spirit',10,10,'stone','[{\"type\": \"water\", \"coords\": [[2, 6], [2, 7], [2, 8], [3, 6], [3, 7], [3, 8], [4, 6], [4, 7], [4, 8]], \"height\": 2}, {\"type\": \"dirt\", \"coords\": [[1, 4]], \"height\": 1}, {\"type\": \"water\", \"coords\": [[5, 4]], \"height\": 1}]','[{\"x\": 0, \"z\": 0}, {\"x\": 1, \"z\": 0}, {\"x\": 0, \"z\": 1}]','[{\"x\": 9, \"z\": 9}, {\"x\": 8, \"z\": 9}, {\"x\": 9, \"z\": 8}]'),(93,9,2,'동래성 전투','부산 함락 후 일본군이